 1	import type { FC } from 'react';
 2	import type { FieldError } from 'react-hook-form';
 3	
 4	import { FormHelperText, HelperText, HelperTextItem } from '@patternfly/react-core';
 5	import { ExclamationCircleIcon } from '@patternfly/react-icons';
 6	import { isEmpty } from '@utils/helpers';
 7	
 8	type FormErrorHelperTextProps = {
 9	  error: FieldError | undefined;
10	  showIcon?: boolean;
11	};
12	
13	export const FormErrorHelperText: FC<FormErrorHelperTextProps> = ({ error, showIcon }) => {
14	  if (isEmpty(error)) {
15	    return null;
16	  }
17	
18	  return (
19	    <FormHelperText>
20	      <HelperText>
21	        <HelperTextItem
22	          icon={showIcon ? <ExclamationCircleIcon /> : null}
23	          variant="error"
24	          data-testid="form-validation-error"
25	        >
26	          {error?.message?.toString()}
27	        </HelperTextItem>
28	      </HelperText>
29	    </FormHelperText>
30	  );
31	};

